#include "interface.h"

#include "zstd.h"

#include <string>

int compress_payload(const std::string& input, std::string& compressed) {
  const size_t input_size = input.size();
  const size_t bound = ZSTD_compressBound(input_size);
  compressed.resize(bound);

  // Favor throughput over ratio versus the baseline's very high level.
  // This preserves lossless correctness while substantially reducing CPU time.
  const int kCompressionLevel = 1;
  const size_t n = ZSTD_compress(
      compressed.data(), bound, input.data(), input_size, kCompressionLevel);

  if (ZSTD_isError(n)) {
    compressed.clear();
    return -1;
  }

  compressed.resize(n);
  return static_cast<int>(n);
}
